//! Deterministic, snapshot-only evaluation of validated IR expressions.
//!
//! Expressions are evaluated in syntax-tree order without reassociation. Real
//! arithmetic therefore uses ordinary IEEE-754 `f64` semantics: in particular,
//! division by zero produces infinity or NaN rather than a runtime error.
//! Aggregate sums make one sequential target-table pass in ascending row order;
//! that order is the canonical Level A CPU reduction order (`DESIGN.md` §5.2).

use std::error::Error;
use std::fmt;

use sembla_ir::{
    AggJoin, AggOp, Aggregate, Attr, AttrType, Expr, ParamType, ParamValue, Table, ValidatedModel,
};

use crate::state::{ColumnData, InputTable, Snapshot, StateError};

/// A typed expression result in query-row order.
#[derive(Clone, Debug, PartialEq)]
pub enum ValueColumn {
    Real(Vec<f64>),
    Int(Vec<i64>),
    Bool(Vec<bool>),
    Enum(Vec<u16>),
}

/// A Ref expression result together with its validator-established target table.
///
/// Ref metadata is kept separate so [`ValueColumn`] retains its frozen four-variant
/// public contract.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RefColumn {
    pub target_table: String,
    pub values: Vec<u32>,
}

impl ValueColumn {
    /// Number of query rows represented by this column.
    pub fn len(&self) -> usize {
        match self {
            Self::Real(values) => values.len(),
            Self::Int(values) => values.len(),
            Self::Bool(values) => values.len(),
            Self::Enum(values) => values.len(),
        }
    }

    /// Whether the result has no query rows.
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }
}

#[derive(Clone, Debug, PartialEq)]
enum InternalColumn {
    Real(Vec<f64>),
    Int(Vec<i64>),
    Bool(Vec<bool>),
    Enum(Vec<u16>),
    Ref(Vec<u32>),
}

impl TryFrom<InternalColumn> for ValueColumn {
    type Error = EvalError;

    fn try_from(column: InternalColumn) -> Result<Self, Self::Error> {
        match column {
            InternalColumn::Real(values) => Ok(Self::Real(values)),
            InternalColumn::Int(values) => Ok(Self::Int(values)),
            InternalColumn::Bool(values) => Ok(Self::Bool(values)),
            InternalColumn::Enum(values) => Ok(Self::Enum(values)),
            InternalColumn::Ref(_) => Err(EvalError::new(
                "top-level Ref expressions are internal-only in PRD 0005",
            )),
        }
    }
}

/// One named per-run parameter override.
#[derive(Clone, Debug, PartialEq)]
pub struct ParamOverride {
    pub name: String,
    pub value: ParamValue,
}

impl ParamOverride {
    pub fn new(name: impl Into<String>, value: ParamValue) -> Self {
        Self {
            name: name.into(),
            value,
        }
    }
}

/// Parameters resolved once from IR defaults and per-run overrides.
///
/// Entries remain in declaration order. Parameter values are never written
/// back into the IR (`DESIGN.md` §4.1).
#[derive(Clone, Debug, PartialEq)]
pub struct ParamEnv {
    values: Vec<(String, ParamValue)>,
}

impl ParamEnv {
    /// Resolves all defaults with no per-run overrides.
    pub fn defaults(model: &ValidatedModel) -> Self {
        Self {
            values: model
                .model()
                .params
                .iter()
                .map(|param| (param.name.clone(), param.default.clone()))
                .collect(),
        }
    }

    /// Resolves defaults overlaid by validated, uniquely named overrides.
    pub fn resolve(model: &ValidatedModel, overrides: &[ParamOverride]) -> Result<Self, EvalError> {
        let mut env = Self::defaults(model);
        for (override_index, parameter_override) in overrides.iter().enumerate() {
            if overrides[..override_index]
                .iter()
                .any(|previous| previous.name == parameter_override.name)
            {
                return Err(EvalError::new(format!(
                    "duplicate override for parameter '{}'",
                    parameter_override.name
                )));
            }
            let declaration = model
                .model()
                .params
                .iter()
                .find(|param| param.name == parameter_override.name)
                .ok_or_else(|| {
                    EvalError::new(format!(
                        "override refers to unknown parameter '{}'",
                        parameter_override.name
                    ))
                })?;
            if !parameter_value_matches(declaration.ty, &parameter_override.value) {
                return Err(EvalError::new(format!(
                    "override for parameter '{}' does not match {:?}",
                    parameter_override.name, declaration.ty
                )));
            }
            if matches!(
                parameter_override.value,
                ParamValue::Real { value } if !value.is_finite()
            ) {
                return Err(EvalError::new(format!(
                    "override for parameter '{}' must be finite",
                    parameter_override.name
                )));
            }
            let entry = env
                .values
                .iter_mut()
                .find(|(name, _)| *name == parameter_override.name)
                .ok_or_else(|| EvalError::new("validated parameter declaration disappeared"))?;
            entry.1 = parameter_override.value.clone();
        }
        Ok(env)
    }

    /// Resolved values in parameter declaration order.
    pub fn values(&self) -> impl Iterator<Item = (&str, &ParamValue)> {
        self.values
            .iter()
            .map(|(name, value)| (name.as_str(), value))
    }

    fn get(&self, name: &str) -> Result<&ParamValue, EvalError> {
        self.values
            .iter()
            .find(|(entry_name, _)| entry_name == name)
            .map(|(_, value)| value)
            .ok_or_else(|| {
                EvalError::new(format!("parameter environment has no value for '{name}'"))
            })
    }
}

/// A table resolved through a [`ValidatedModel`].
///
/// The private indices preserve box qualification when different boxes use the
/// same local table name.
#[derive(Clone, Copy, Debug)]
pub struct EvalTable<'model> {
    model: &'model ValidatedModel,
    box_index: usize,
    table_index: usize,
    expected_attr_index: Option<usize>,
}

impl<'model> EvalTable<'model> {
    pub fn new(
        model: &'model ValidatedModel,
        box_name: &str,
        table_name: &str,
    ) -> Result<Self, EvalError> {
        let box_index = model
            .model()
            .boxes
            .iter()
            .position(|model_box| model_box.name == box_name)
            .ok_or_else(|| EvalError::new(format!("unknown box '{box_name}'")))?;
        let table_index = model.model().boxes[box_index]
            .tables
            .iter()
            .position(|table| table.name == table_name)
            .ok_or_else(|| {
                EvalError::new(format!(
                    "box '{box_name}' has no table named '{table_name}'"
                ))
            })?;
        Ok(Self {
            model,
            box_index,
            table_index,
            expected_attr_index: None,
        })
    }

    pub fn box_name(&self) -> &str {
        &self.model_box().name
    }

    pub fn table_name(&self) -> &str {
        &self.schema().name
    }

    /// Supplies the validator-established destination attribute context.
    pub fn with_expected_attr(mut self, attr_name: &str) -> Result<Self, EvalError> {
        self.expected_attr_index = Some(
            self.schema()
                .attrs
                .iter()
                .position(|attr| attr.name == attr_name)
                .ok_or_else(|| {
                    EvalError::new(format!(
                        "table '{}' has no expected attribute '{attr_name}'",
                        self.table_name()
                    ))
                })?,
        );
        Ok(self)
    }

    fn expected_type(&self) -> Option<RuntimeType> {
        self.expected_attr_index
            .map(|index| RuntimeType::from(&self.schema().attrs[index].ty))
    }

    fn model_box(&self) -> &sembla_ir::Box {
        &self.model.model().boxes[self.box_index]
    }

    fn schema(&self) -> &Table {
        &self.model_box().tables[self.table_index]
    }

    fn target(&self, table_name: &str) -> Result<Self, EvalError> {
        Self::new(self.model, self.box_name(), table_name)
    }
}

#[derive(Clone, Debug)]
struct AggregateKey {
    box_name: String,
    table: String,
    op: AggOp,
    on: AggJoin,
    filter: Expr,
}

impl PartialEq for AggregateKey {
    fn eq(&self, other: &Self) -> bool {
        self.box_name == other.box_name
            && self.table == other.table
            && self.on == other.on
            && agg_op_structural_eq(&self.op, &other.op)
            && expr_structural_eq(&self.filter, &other.filter)
    }
}

fn agg_op_structural_eq(lhs: &AggOp, rhs: &AggOp) -> bool {
    match (lhs, rhs) {
        (AggOp::Count, AggOp::Count) => true,
        (AggOp::Sum { value: lhs }, AggOp::Sum { value: rhs }) => expr_structural_eq(lhs, rhs),
        _ => false,
    }
}

fn aggregate_structural_eq(lhs: &sembla_ir::Aggregate, rhs: &sembla_ir::Aggregate) -> bool {
    agg_op_structural_eq(&lhs.op, &rhs.op)
        && match (&lhs.filter, &rhs.filter) {
            (Some(lhs), Some(rhs)) => expr_structural_eq(lhs, rhs),
            (None, None) => true,
            _ => false,
        }
}

fn binary_expr_eq(lhs_left: &Expr, lhs_right: &Expr, rhs_left: &Expr, rhs_right: &Expr) -> bool {
    expr_structural_eq(lhs_left, rhs_left) && expr_structural_eq(lhs_right, rhs_right)
}

fn expr_structural_eq(lhs: &Expr, rhs: &Expr) -> bool {
    match (lhs, rhs) {
        (Expr::Real { value: lhs }, Expr::Real { value: rhs }) => lhs.to_bits() == rhs.to_bits(),
        (Expr::Int { value: lhs }, Expr::Int { value: rhs }) => lhs == rhs,
        (Expr::Bool { value: lhs }, Expr::Bool { value: rhs }) => lhs == rhs,
        (Expr::Enum { variant: lhs }, Expr::Enum { variant: rhs }) => lhs == rhs,
        (Expr::Param { name: lhs }, Expr::Param { name: rhs }) => lhs == rhs,
        (Expr::SelfAttr { name: lhs }, Expr::SelfAttr { name: rhs }) => lhs == rhs,
        (
            Expr::Add {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Add {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Sub {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Sub {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Mul {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Mul {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Div {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Div {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Eq {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Eq {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Ne {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Ne {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Lt {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Lt {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Le {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Le {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Gt {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Gt {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Ge {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Ge {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::And {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::And {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        )
        | (
            Expr::Or {
                lhs: lhs_left,
                rhs: lhs_right,
            },
            Expr::Or {
                lhs: rhs_left,
                rhs: rhs_right,
            },
        ) => binary_expr_eq(lhs_left, lhs_right, rhs_left, rhs_right),
        (Expr::Not { expr: lhs }, Expr::Not { expr: rhs }) => expr_structural_eq(lhs, rhs),
        (
            Expr::EnumIs {
                attr: lhs_attr,
                variant: lhs_variant,
            },
            Expr::EnumIs {
                attr: rhs_attr,
                variant: rhs_variant,
            },
        ) => lhs_attr == rhs_attr && lhs_variant == rhs_variant,
        (
            Expr::Input {
                port: lhs_port,
                agg: lhs_agg,
            },
            Expr::Input {
                port: rhs_port,
                agg: rhs_agg,
            },
        ) => lhs_port == rhs_port && aggregate_structural_eq(lhs_agg, rhs_agg),
        (
            Expr::Agg {
                op: lhs_op,
                table: lhs_table,
                on: lhs_on,
                filter: lhs_filter,
            },
            Expr::Agg {
                op: rhs_op,
                table: rhs_table,
                on: rhs_on,
                filter: rhs_filter,
            },
        ) => {
            lhs_table == rhs_table
                && lhs_on == rhs_on
                && agg_op_structural_eq(lhs_op, rhs_op)
                && expr_structural_eq(lhs_filter, rhs_filter)
        }
        _ => false,
    }
}

#[derive(Clone, Debug, PartialEq)]
enum Accumulator {
    Int(Vec<i64>),
    Real(Vec<f64>),
}

#[derive(Clone, Debug)]
struct CacheEntry {
    key: AggregateKey,
    values: Accumulator,
}

/// Aggregate accumulators bound to one validated model and tick input scope.
///
/// Holding these references prevents allocator address reuse while entries are
/// live. A fresh cache is required for each snapshot/parameter scope.
#[derive(Clone, Debug)]
pub struct AggCache<'tick, 'state> {
    model: &'tick ValidatedModel,
    snapshot: &'tick Snapshot<'state>,
    params: &'tick ParamEnv,
    entries: Vec<CacheEntry>,
    build_count: usize,
}

impl<'tick, 'state> AggCache<'tick, 'state> {
    pub fn new(
        model: &'tick ValidatedModel,
        snapshot: &'tick Snapshot<'state>,
        params: &'tick ParamEnv,
    ) -> Self {
        Self {
            model,
            snapshot,
            params,
            entries: Vec::new(),
            build_count: 0,
        }
    }

    /// Returns the exact tick-start snapshot bound to this cache.
    pub fn snapshot(&self) -> &'tick Snapshot<'state> {
        self.snapshot
    }

    /// Number of structurally distinct aggregate accumulators currently held.
    pub fn len(&self) -> usize {
        self.entries.len()
    }

    pub fn is_empty(&self) -> bool {
        self.entries.is_empty()
    }

    /// Successful accumulator builds in this tick scope.
    pub fn build_count(&self) -> usize {
        self.build_count
    }

    /// Drops every accumulator while retaining the same tick scope.
    pub fn clear(&mut self) {
        self.entries.clear();
        self.build_count = 0;
    }

    fn validate_scope(
        &self,
        table: EvalTable<'_>,
        snapshot: &Snapshot<'_>,
        params: &ParamEnv,
    ) -> Result<(), EvalError> {
        if !std::ptr::eq(self.model, table.model) {
            return Err(EvalError::new(
                "aggregate cache belongs to a different model",
            ));
        }
        if !std::ptr::eq(self.snapshot, snapshot) {
            return Err(EvalError::new(
                "aggregate cache belongs to a different Snapshot object",
            ));
        }
        if !std::ptr::eq(self.params, params) {
            return Err(EvalError::new(
                "aggregate cache belongs to a different parameter environment",
            ));
        }
        Ok(())
    }
}

/// A deterministic evaluation failure.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct EvalError {
    message: String,
}

impl EvalError {
    fn new(message: impl Into<String>) -> Self {
        Self {
            message: message.into(),
        }
    }
}

impl fmt::Display for EvalError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        formatter.write_str(&self.message)
    }
}

impl Error for EvalError {}

impl From<StateError> for EvalError {
    fn from(error: StateError) -> Self {
        Self::new(error.to_string())
    }
}

#[derive(Clone, Debug, PartialEq, Eq)]
enum RuntimeType {
    Real,
    Int,
    Bool,
    Enum(Vec<String>),
    Ref(String),
}

impl RuntimeType {
    fn name(&self) -> &'static str {
        match self {
            Self::Real => "Real",
            Self::Int => "Int",
            Self::Bool => "Bool",
            Self::Enum(_) => "Enum",
            Self::Ref(_) => "Ref",
        }
    }

    fn is_numeric(&self) -> bool {
        matches!(self, Self::Real | Self::Int)
    }
}

impl From<&AttrType> for RuntimeType {
    fn from(value: &AttrType) -> Self {
        match value {
            AttrType::Real => Self::Real,
            AttrType::Int => Self::Int,
            AttrType::Enum { variants } => Self::Enum(variants.clone()),
            AttrType::Ref { table } => Self::Ref(table.clone()),
        }
    }
}

fn infer_root_type(expr: &Expr, table: EvalTable<'_>) -> Result<RuntimeType, EvalError> {
    let expected = table.expected_type();
    let actual = infer_expr_type(expr, table, &table.schema().attrs, expected.as_ref())?;
    if let Some(expected) = expected {
        require_type(&actual, &expected)?;
    }
    Ok(actual)
}

/// Evaluates one validated expression for every row in `table`.
///
/// Only an immutable [`Snapshot`] is accepted, so same-tick writes are
/// inaccessible. Evaluation follows the expression tree exactly; `f64`
/// division by zero deliberately retains IEEE infinity/NaN semantics.
pub fn eval_column(
    expr: &Expr,
    table: EvalTable<'_>,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    agg_cache: &mut AggCache<'_, '_>,
) -> Result<ValueColumn, EvalError> {
    agg_cache.validate_scope(table, snapshot, params)?;
    let inferred = infer_root_type(expr, table)?;
    ValueColumn::try_from(eval_expr(
        expr,
        table,
        &table.schema().attrs,
        snapshot,
        params,
        agg_cache,
        Some(&inferred),
    )?)
}

/// Evaluates a Ref-typed root expression without extending [`ValueColumn`].
///
/// Ref values remain available to later runtime stages such as resource-claim
/// evaluation, while the PRD 0005 public value-column contract stays limited to
/// Real, Int, Bool, and Enum columns.
pub fn eval_ref_column(
    expr: &Expr,
    table: EvalTable<'_>,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    agg_cache: &mut AggCache<'_, '_>,
) -> Result<Vec<u32>, EvalError> {
    Ok(eval_typed_ref_column(expr, table, snapshot, params, agg_cache)?.values)
}

/// Evaluates a Ref-typed root expression and preserves its target-table type.
pub fn eval_typed_ref_column(
    expr: &Expr,
    table: EvalTable<'_>,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    agg_cache: &mut AggCache<'_, '_>,
) -> Result<RefColumn, EvalError> {
    agg_cache.validate_scope(table, snapshot, params)?;
    let inferred = infer_root_type(expr, table)?;
    let RuntimeType::Ref(target_table) = &inferred else {
        return Err(EvalError::new(format!(
            "expected Ref expression, found {}",
            inferred.name()
        )));
    };
    match eval_expr(
        expr,
        table,
        &table.schema().attrs,
        snapshot,
        params,
        agg_cache,
        Some(&inferred),
    )? {
        InternalColumn::Ref(values) => Ok(RefColumn {
            target_table: target_table.clone(),
            values,
        }),
        _ => Err(EvalError::new(
            "Ref-typed expression did not evaluate to Ref values",
        )),
    }
}

fn eval_expr(
    expr: &Expr,
    table: EvalTable<'_>,
    row_attrs: &[Attr],
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    cache: &mut AggCache<'_, '_>,
    expected: Option<&RuntimeType>,
) -> Result<InternalColumn, EvalError> {
    let row_count = snapshot.row_count(table.box_name(), table.table_name())?;
    match expr {
        Expr::Real { value } => Ok(InternalColumn::Real(vec![*value; row_count])),
        Expr::Int { value } => Ok(InternalColumn::Int(vec![*value; row_count])),
        Expr::Bool { value } => Ok(InternalColumn::Bool(vec![*value; row_count])),
        Expr::Enum { variant } => {
            let RuntimeType::Enum(variants) = expected.ok_or_else(|| {
                EvalError::new(format!("enum literal '{variant}' has no type context"))
            })?
            else {
                return Err(EvalError::new(format!(
                    "enum literal '{variant}' requires an Enum context"
                )));
            };
            let index = variants
                .iter()
                .position(|candidate| candidate == variant)
                .ok_or_else(|| EvalError::new(format!("unknown enum variant '{variant}'")))?;
            let index = u16::try_from(index)
                .map_err(|_| EvalError::new(format!("enum variant '{variant}' exceeds u16")))?;
            Ok(InternalColumn::Enum(vec![index; row_count]))
        }
        Expr::Param { name } => {
            let declaration = table
                .model
                .model()
                .params
                .iter()
                .find(|param| param.name == *name)
                .ok_or_else(|| EvalError::new(format!("unresolved parameter '{name}'")))?;
            match (declaration.ty, params.get(name)?) {
                (ParamType::Real, ParamValue::Real { value }) => {
                    Ok(InternalColumn::Real(vec![*value; row_count]))
                }
                (ParamType::Int, ParamValue::Int { value }) => {
                    Ok(InternalColumn::Int(vec![*value; row_count]))
                }
                _ => Err(EvalError::new(format!(
                    "parameter environment value for '{name}' has the wrong type"
                ))),
            }
        }
        Expr::SelfAttr { name } => eval_self_attr(table, row_attrs, snapshot, name, row_count),
        Expr::Add { lhs, rhs } => eval_arithmetic(
            Arithmetic::Add,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Sub { lhs, rhs } => eval_arithmetic(
            Arithmetic::Sub,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Mul { lhs, rhs } => eval_arithmetic(
            Arithmetic::Mul,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Div { lhs, rhs } => eval_arithmetic(
            Arithmetic::Div,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Eq { lhs, rhs } => {
            eval_equality(false, lhs, rhs, table, row_attrs, snapshot, params, cache)
        }
        Expr::Ne { lhs, rhs } => {
            eval_equality(true, lhs, rhs, table, row_attrs, snapshot, params, cache)
        }
        Expr::Lt { lhs, rhs } => eval_ordering(
            Ordering::Lt,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Le { lhs, rhs } => eval_ordering(
            Ordering::Le,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Gt { lhs, rhs } => eval_ordering(
            Ordering::Gt,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::Ge { lhs, rhs } => eval_ordering(
            Ordering::Ge,
            lhs,
            rhs,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
        ),
        Expr::And { lhs, rhs } | Expr::Or { lhs, rhs } => {
            let lhs = eval_expr(lhs, table, row_attrs, snapshot, params, cache, None)?;
            let rhs = eval_expr(rhs, table, row_attrs, snapshot, params, cache, None)?;
            let (InternalColumn::Bool(lhs), InternalColumn::Bool(rhs)) = (lhs, rhs) else {
                return Err(EvalError::new("boolean operands did not evaluate to Bool"));
            };
            let values = lhs
                .into_iter()
                .zip(rhs)
                .map(|(lhs, rhs)| {
                    if matches!(expr, Expr::And { .. }) {
                        lhs && rhs
                    } else {
                        lhs || rhs
                    }
                })
                .collect();
            Ok(InternalColumn::Bool(values))
        }
        Expr::Not { expr } => {
            let values = eval_expr(expr, table, row_attrs, snapshot, params, cache, None)?;
            let InternalColumn::Bool(values) = values else {
                return Err(EvalError::new("Not operand did not evaluate to Bool"));
            };
            Ok(InternalColumn::Bool(
                values.into_iter().map(|value| !value).collect(),
            ))
        }
        Expr::EnumIs { attr, variant } => {
            let declaration = find_attr(row_attrs, attr)?;
            let AttrType::Enum { variants } = &declaration.ty else {
                return Err(EvalError::new(format!(
                    "EnumIs attribute '{attr}' is not Enum-typed"
                )));
            };
            let variant = variants
                .iter()
                .position(|candidate| candidate == variant)
                .ok_or_else(|| EvalError::new(format!("unknown enum variant for '{attr}'")))?;
            let variant = u16::try_from(variant)
                .map_err(|_| EvalError::new(format!("enum attribute '{attr}' exceeds u16")))?;
            let mut values = Vec::with_capacity(row_count);
            for row in 0..row_count {
                values.push(
                    snapshot.enum_index(table.box_name(), table.table_name(), attr, row)?
                        == variant,
                );
            }
            Ok(InternalColumn::Bool(values))
        }
        Expr::Input { port, agg } => {
            let declaration = table
                .model_box()
                .inputs
                .iter()
                .find(|input| input.name == *port)
                .ok_or_else(|| EvalError::new("validated input port disappeared"))?;
            let result_type = infer_agg_type(&agg.op, table, &declaration.schema)?;
            let input = snapshot.input_table(table.box_name(), port)?;
            eval_input_aggregate(input, agg, params, row_count, &result_type)
        }
        Expr::Agg {
            op,
            table: target,
            on,
            filter,
        } => eval_aggregate(op, target, on, filter, table, snapshot, params, cache),
    }
}

#[derive(Clone, Copy, Debug)]
enum InputScalar {
    Real(f64),
    Int(i64),
    Bool(bool),
    Enum(u16),
    Ref(u32),
}

fn eval_input_aggregate(
    input: &InputTable,
    agg: &Aggregate,
    params: &ParamEnv,
    result_rows: usize,
    result_type: &RuntimeType,
) -> Result<InternalColumn, EvalError> {
    let mut selected = Vec::with_capacity(input.row_count);
    for row in 0..input.row_count {
        let keep = match &agg.filter {
            Some(filter) => match eval_input_scalar(filter, input, row, params)? {
                InputScalar::Bool(value) => value,
                _ => return Err(EvalError::new("input aggregate filter is not Bool")),
            },
            None => true,
        };
        selected.push(keep);
    }
    match &agg.op {
        AggOp::Count => {
            let count = selected.iter().filter(|value| **value).count();
            let count = i64::try_from(count)
                .map_err(|_| EvalError::new("input aggregate count exceeds i64"))?;
            Ok(InternalColumn::Int(vec![count; result_rows]))
        }
        AggOp::Sum { value } => {
            let mut int_sum = 0_i64;
            let mut real_sum = 0.0;
            let mut real = matches!(result_type, RuntimeType::Real);
            for (row, keep) in selected.into_iter().enumerate() {
                if !keep {
                    continue;
                }
                match eval_input_scalar(value, input, row, params)? {
                    InputScalar::Int(value) if !real => {
                        int_sum = int_sum.checked_add(value).ok_or_else(|| {
                            EvalError::new(format!("input aggregate integer overflow at row {row}"))
                        })?;
                    }
                    InputScalar::Int(value) => real_sum += value as f64,
                    InputScalar::Real(value) => {
                        if !real {
                            real_sum = int_sum as f64;
                            real = true;
                        }
                        real_sum += value;
                    }
                    _ => return Err(EvalError::new("input aggregate Sum value is not numeric")),
                }
            }
            match result_type {
                RuntimeType::Real => Ok(InternalColumn::Real(vec![real_sum; result_rows])),
                RuntimeType::Int => Ok(InternalColumn::Int(vec![int_sum; result_rows])),
                _ => Err(EvalError::new("input aggregate Sum has non-numeric type")),
            }
        }
    }
}

fn eval_input_scalar(
    expr: &Expr,
    input: &InputTable,
    row: usize,
    params: &ParamEnv,
) -> Result<InputScalar, EvalError> {
    match expr {
        Expr::Real { value } => Ok(InputScalar::Real(*value)),
        Expr::Int { value } => Ok(InputScalar::Int(*value)),
        Expr::Bool { value } => Ok(InputScalar::Bool(*value)),
        Expr::Param { name } => match params.get(name)? {
            ParamValue::Real { value } => Ok(InputScalar::Real(*value)),
            ParamValue::Int { value } => Ok(InputScalar::Int(*value)),
        },
        Expr::SelfAttr { name } => input_scalar_attr(input, name, row),
        Expr::EnumIs { attr, variant } => {
            let declaration = find_attr(&input.schema, attr)?;
            let AttrType::Enum { variants } = &declaration.ty else {
                return Err(EvalError::new(format!(
                    "EnumIs attribute '{attr}' is not Enum-typed"
                )));
            };
            let expected = variants
                .iter()
                .position(|candidate| candidate == variant)
                .ok_or_else(|| EvalError::new(format!("unknown enum variant '{variant}'")))?;
            match input_scalar_attr(input, attr, row)? {
                InputScalar::Enum(value) => Ok(InputScalar::Bool(usize::from(value) == expected)),
                _ => unreachable!("schema and input column type disagree"),
            }
        }
        Expr::Add { lhs, rhs }
        | Expr::Sub { lhs, rhs }
        | Expr::Mul { lhs, rhs }
        | Expr::Div { lhs, rhs } => {
            let lhs = eval_input_scalar(lhs, input, row, params)?;
            let rhs = eval_input_scalar(rhs, input, row, params)?;
            input_arithmetic(expr, lhs, rhs, row)
        }
        Expr::Eq { lhs, rhs } | Expr::Ne { lhs, rhs } => {
            let (lhs_value, rhs_value) = match (lhs.as_ref(), rhs.as_ref()) {
                (Expr::Enum { variant }, _) => (
                    input_enum_literal(input, rhs, variant)?,
                    eval_input_scalar(rhs, input, row, params)?,
                ),
                (_, Expr::Enum { variant }) => (
                    eval_input_scalar(lhs, input, row, params)?,
                    input_enum_literal(input, lhs, variant)?,
                ),
                _ => (
                    eval_input_scalar(lhs, input, row, params)?,
                    eval_input_scalar(rhs, input, row, params)?,
                ),
            };
            let equal = match (lhs_value, rhs_value) {
                (InputScalar::Real(lhs), InputScalar::Real(rhs)) => lhs == rhs,
                (InputScalar::Real(lhs), InputScalar::Int(rhs)) => lhs == rhs as f64,
                (InputScalar::Int(lhs), InputScalar::Real(rhs)) => lhs as f64 == rhs,
                (InputScalar::Int(lhs), InputScalar::Int(rhs)) => lhs == rhs,
                (InputScalar::Bool(lhs), InputScalar::Bool(rhs)) => lhs == rhs,
                (InputScalar::Enum(lhs), InputScalar::Enum(rhs)) => lhs == rhs,
                (InputScalar::Ref(lhs), InputScalar::Ref(rhs)) => lhs == rhs,
                _ => {
                    return Err(EvalError::new(
                        "input equality operands have incompatible types",
                    ))
                }
            };
            Ok(InputScalar::Bool(if matches!(expr, Expr::Ne { .. }) {
                !equal
            } else {
                equal
            }))
        }
        Expr::Lt { lhs, rhs }
        | Expr::Le { lhs, rhs }
        | Expr::Gt { lhs, rhs }
        | Expr::Ge { lhs, rhs } => {
            let lhs = input_number(eval_input_scalar(lhs, input, row, params)?)?;
            let rhs = input_number(eval_input_scalar(rhs, input, row, params)?)?;
            let value = match expr {
                Expr::Lt { .. } => lhs < rhs,
                Expr::Le { .. } => lhs <= rhs,
                Expr::Gt { .. } => lhs > rhs,
                Expr::Ge { .. } => lhs >= rhs,
                _ => unreachable!(),
            };
            Ok(InputScalar::Bool(value))
        }
        Expr::And { lhs, rhs } | Expr::Or { lhs, rhs } => {
            let InputScalar::Bool(lhs) = eval_input_scalar(lhs, input, row, params)? else {
                return Err(EvalError::new("input boolean lhs is not Bool"));
            };
            let InputScalar::Bool(rhs) = eval_input_scalar(rhs, input, row, params)? else {
                return Err(EvalError::new("input boolean rhs is not Bool"));
            };
            Ok(InputScalar::Bool(if matches!(expr, Expr::And { .. }) {
                lhs && rhs
            } else {
                lhs || rhs
            }))
        }
        Expr::Not { expr } => match eval_input_scalar(expr, input, row, params)? {
            InputScalar::Bool(value) => Ok(InputScalar::Bool(!value)),
            _ => Err(EvalError::new("input Not operand is not Bool")),
        },
        Expr::Enum { .. } => Err(EvalError::new(
            "bare enum literals are not supported in input aggregates; use EnumIs",
        )),
        Expr::Input { .. } | Expr::Agg { .. } => Err(EvalError::new(
            "nested aggregates are not supported inside input table aggregates",
        )),
    }
}

fn input_enum_literal(
    input: &InputTable,
    context: &Expr,
    variant: &str,
) -> Result<InputScalar, EvalError> {
    let Expr::SelfAttr { name } = context else {
        return Err(EvalError::new(
            "input enum literal requires a direct Enum attribute context",
        ));
    };
    let declaration = find_attr(&input.schema, name)?;
    let AttrType::Enum { variants } = &declaration.ty else {
        return Err(EvalError::new("input enum literal context is not Enum"));
    };
    let index = variants
        .iter()
        .position(|candidate| candidate == variant)
        .ok_or_else(|| EvalError::new(format!("unknown enum variant '{variant}'")))?;
    Ok(InputScalar::Enum(u16::try_from(index).map_err(|_| {
        EvalError::new("input enum variant index exceeds u16")
    })?))
}

fn input_scalar_attr(input: &InputTable, name: &str, row: usize) -> Result<InputScalar, EvalError> {
    match input
        .column(name)
        .ok_or_else(|| EvalError::new(format!("input table has no column '{name}'")))?
    {
        ColumnData::Real(values) => values.get(row).copied().map(InputScalar::Real),
        ColumnData::Int(values) => values.get(row).copied().map(InputScalar::Int),
        ColumnData::Enum(values) => values.get(row).copied().map(InputScalar::Enum),
        ColumnData::Ref(values) => values.get(row).copied().map(InputScalar::Ref),
    }
    .ok_or_else(|| EvalError::new(format!("input column '{name}' has no row {row}")))
}

fn input_number(value: InputScalar) -> Result<f64, EvalError> {
    match value {
        InputScalar::Real(value) => Ok(value),
        InputScalar::Int(value) => Ok(value as f64),
        _ => Err(EvalError::new("input ordered operand is not numeric")),
    }
}

fn input_arithmetic(
    expr: &Expr,
    lhs: InputScalar,
    rhs: InputScalar,
    row: usize,
) -> Result<InputScalar, EvalError> {
    if matches!(expr, Expr::Div { .. })
        || matches!(lhs, InputScalar::Real(_))
        || matches!(rhs, InputScalar::Real(_))
    {
        let lhs = input_number(lhs)?;
        let rhs = input_number(rhs)?;
        return Ok(InputScalar::Real(match expr {
            Expr::Add { .. } => lhs + rhs,
            Expr::Sub { .. } => lhs - rhs,
            Expr::Mul { .. } => lhs * rhs,
            Expr::Div { .. } => lhs / rhs,
            _ => unreachable!(),
        }));
    }
    let (InputScalar::Int(lhs), InputScalar::Int(rhs)) = (lhs, rhs) else {
        return Err(EvalError::new("input arithmetic operands are not numeric"));
    };
    let value = match expr {
        Expr::Add { .. } => lhs.checked_add(rhs),
        Expr::Sub { .. } => lhs.checked_sub(rhs),
        Expr::Mul { .. } => lhs.checked_mul(rhs),
        _ => unreachable!(),
    }
    .ok_or_else(|| EvalError::new(format!("input integer arithmetic overflow at row {row}")))?;
    Ok(InputScalar::Int(value))
}

fn eval_self_attr(
    table: EvalTable<'_>,
    row_attrs: &[Attr],
    snapshot: &Snapshot<'_>,
    name: &str,
    row_count: usize,
) -> Result<InternalColumn, EvalError> {
    let attr = find_attr(row_attrs, name)?;
    match &attr.ty {
        AttrType::Real => (0..row_count)
            .map(|row| snapshot.real(table.box_name(), table.table_name(), name, row))
            .collect::<Result<Vec<_>, _>>()
            .map(InternalColumn::Real)
            .map_err(Into::into),
        AttrType::Int => (0..row_count)
            .map(|row| snapshot.int(table.box_name(), table.table_name(), name, row))
            .collect::<Result<Vec<_>, _>>()
            .map(InternalColumn::Int)
            .map_err(Into::into),
        AttrType::Enum { .. } => (0..row_count)
            .map(|row| snapshot.enum_index(table.box_name(), table.table_name(), name, row))
            .collect::<Result<Vec<_>, _>>()
            .map(InternalColumn::Enum)
            .map_err(Into::into),
        AttrType::Ref { .. } => (0..row_count)
            .map(|row| snapshot.reference(table.box_name(), table.table_name(), name, row))
            .collect::<Result<Vec<_>, _>>()
            .map(InternalColumn::Ref)
            .map_err(Into::into),
    }
}

#[derive(Clone, Copy)]
enum Arithmetic {
    Add,
    Sub,
    Mul,
    Div,
}

#[allow(clippy::too_many_arguments)]
fn eval_arithmetic(
    operation: Arithmetic,
    lhs: &Expr,
    rhs: &Expr,
    table: EvalTable<'_>,
    row_attrs: &[Attr],
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    cache: &mut AggCache<'_, '_>,
) -> Result<InternalColumn, EvalError> {
    let lhs = eval_expr(lhs, table, row_attrs, snapshot, params, cache, None)?;
    let rhs = eval_expr(rhs, table, row_attrs, snapshot, params, cache, None)?;
    if matches!(operation, Arithmetic::Div)
        || matches!(lhs, InternalColumn::Real(_))
        || matches!(rhs, InternalColumn::Real(_))
    {
        let lhs = numeric_as_real(&lhs)?;
        let rhs = numeric_as_real(&rhs)?;
        return Ok(InternalColumn::Real(
            lhs.into_iter()
                .zip(rhs)
                .map(|(lhs, rhs)| match operation {
                    Arithmetic::Add => lhs + rhs,
                    Arithmetic::Sub => lhs - rhs,
                    Arithmetic::Mul => lhs * rhs,
                    Arithmetic::Div => lhs / rhs,
                })
                .collect(),
        ));
    }
    let (InternalColumn::Int(lhs), InternalColumn::Int(rhs)) = (lhs, rhs) else {
        return Err(EvalError::new("arithmetic operands are not numeric"));
    };
    let values = lhs
        .into_iter()
        .zip(rhs)
        .enumerate()
        .map(|(row, (lhs, rhs))| {
            let value = match operation {
                Arithmetic::Add => lhs.checked_add(rhs),
                Arithmetic::Sub => lhs.checked_sub(rhs),
                Arithmetic::Mul => lhs.checked_mul(rhs),
                Arithmetic::Div => unreachable!("division promotes to Real"),
            };
            value.ok_or_else(|| EvalError::new(format!("integer arithmetic overflow at row {row}")))
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok(InternalColumn::Int(values))
}

#[allow(clippy::too_many_arguments)]
fn eval_equality(
    negate: bool,
    lhs_expr: &Expr,
    rhs_expr: &Expr,
    table: EvalTable<'_>,
    row_attrs: &[Attr],
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    cache: &mut AggCache<'_, '_>,
) -> Result<InternalColumn, EvalError> {
    let (lhs, rhs) = if matches!(lhs_expr, Expr::Enum { .. }) {
        let rhs_type = infer_expr_type(rhs_expr, table, row_attrs, None)?;
        let rhs = eval_expr(rhs_expr, table, row_attrs, snapshot, params, cache, None)?;
        let lhs = eval_expr(
            lhs_expr,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
            Some(&rhs_type),
        )?;
        (lhs, rhs)
    } else {
        let lhs_type = infer_expr_type(lhs_expr, table, row_attrs, None)?;
        let lhs = eval_expr(lhs_expr, table, row_attrs, snapshot, params, cache, None)?;
        let rhs = eval_expr(
            rhs_expr,
            table,
            row_attrs,
            snapshot,
            params,
            cache,
            Some(&lhs_type),
        )?;
        (lhs, rhs)
    };
    let equal = equal_columns(&lhs, &rhs)?;
    Ok(InternalColumn::Bool(
        equal
            .into_iter()
            .map(|value| if negate { !value } else { value })
            .collect(),
    ))
}

fn equal_columns(lhs: &InternalColumn, rhs: &InternalColumn) -> Result<Vec<bool>, EvalError> {
    if let (InternalColumn::Int(lhs), InternalColumn::Int(rhs)) = (lhs, rhs) {
        return Ok(lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect());
    }
    if matches!(lhs, InternalColumn::Real(_) | InternalColumn::Int(_))
        && matches!(rhs, InternalColumn::Real(_) | InternalColumn::Int(_))
    {
        return Ok(numeric_as_real(lhs)?
            .into_iter()
            .zip(numeric_as_real(rhs)?)
            .map(|(lhs, rhs)| lhs == rhs)
            .collect());
    }
    let values = match (lhs, rhs) {
        (InternalColumn::Bool(lhs), InternalColumn::Bool(rhs)) => {
            lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect()
        }
        (InternalColumn::Enum(lhs), InternalColumn::Enum(rhs)) => {
            lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect()
        }
        (InternalColumn::Ref(lhs), InternalColumn::Ref(rhs)) => {
            lhs.iter().zip(rhs).map(|(lhs, rhs)| lhs == rhs).collect()
        }
        _ => return Err(EvalError::new("equality operands have incompatible types")),
    };
    Ok(values)
}

#[derive(Clone, Copy)]
enum Ordering {
    Lt,
    Le,
    Gt,
    Ge,
}

#[allow(clippy::too_many_arguments)]
fn eval_ordering(
    operation: Ordering,
    lhs: &Expr,
    rhs: &Expr,
    table: EvalTable<'_>,
    row_attrs: &[Attr],
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    cache: &mut AggCache<'_, '_>,
) -> Result<InternalColumn, EvalError> {
    let lhs = eval_expr(lhs, table, row_attrs, snapshot, params, cache, None)?;
    let rhs = eval_expr(rhs, table, row_attrs, snapshot, params, cache, None)?;
    if let (InternalColumn::Int(lhs), InternalColumn::Int(rhs)) = (&lhs, &rhs) {
        return Ok(InternalColumn::Bool(
            lhs.iter()
                .zip(rhs)
                .map(|(lhs, rhs)| match operation {
                    Ordering::Lt => lhs < rhs,
                    Ordering::Le => lhs <= rhs,
                    Ordering::Gt => lhs > rhs,
                    Ordering::Ge => lhs >= rhs,
                })
                .collect(),
        ));
    }
    let lhs = numeric_as_real(&lhs)?;
    let rhs = numeric_as_real(&rhs)?;
    Ok(InternalColumn::Bool(
        lhs.into_iter()
            .zip(rhs)
            .map(|(lhs, rhs)| match operation {
                Ordering::Lt => lhs < rhs,
                Ordering::Le => lhs <= rhs,
                Ordering::Gt => lhs > rhs,
                Ordering::Ge => lhs >= rhs,
            })
            .collect(),
    ))
}

fn numeric_as_real(column: &InternalColumn) -> Result<Vec<f64>, EvalError> {
    match column {
        InternalColumn::Real(values) => Ok(values.clone()),
        InternalColumn::Int(values) => Ok(values.iter().map(|value| *value as f64).collect()),
        _ => Err(EvalError::new(
            "numeric expression did not evaluate to Real or Int",
        )),
    }
}

#[allow(clippy::too_many_arguments)]
fn eval_aggregate(
    op: &AggOp,
    target_name: &str,
    on: &AggJoin,
    filter: &Expr,
    query: EvalTable<'_>,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    cache: &mut AggCache<'_, '_>,
) -> Result<InternalColumn, EvalError> {
    let key = AggregateKey {
        box_name: query.box_name().to_owned(),
        table: target_name.to_owned(),
        op: op.clone(),
        on: on.clone(),
        filter: filter.clone(),
    };
    let accumulator = if let Some(entry) = cache.entries.iter().find(|entry| entry.key == key) {
        entry.values.clone()
    } else {
        let values = build_aggregate(op, target_name, on, filter, query, snapshot, params, cache)?;
        cache.entries.push(CacheEntry {
            key,
            values: values.clone(),
        });
        cache.build_count += 1;
        values
    };

    let query_rows = snapshot.row_count(query.box_name(), query.table_name())?;
    match accumulator {
        Accumulator::Int(groups) => {
            let mut values = Vec::with_capacity(query_rows);
            for row in 0..query_rows {
                let group = snapshot.reference(
                    query.box_name(),
                    query.table_name(),
                    &on.self_fk_attr,
                    row,
                )? as usize;
                values.push(*groups.get(group).ok_or_else(|| {
                    EvalError::new(format!(
                        "aggregate broadcast group {group} is out of bounds"
                    ))
                })?);
            }
            Ok(InternalColumn::Int(values))
        }
        Accumulator::Real(groups) => {
            let mut values = Vec::with_capacity(query_rows);
            for row in 0..query_rows {
                let group = snapshot.reference(
                    query.box_name(),
                    query.table_name(),
                    &on.self_fk_attr,
                    row,
                )? as usize;
                values.push(*groups.get(group).ok_or_else(|| {
                    EvalError::new(format!(
                        "aggregate broadcast group {group} is out of bounds"
                    ))
                })?);
            }
            Ok(InternalColumn::Real(values))
        }
    }
}

#[allow(clippy::too_many_arguments)]
fn build_aggregate(
    op: &AggOp,
    target_name: &str,
    on: &AggJoin,
    filter: &Expr,
    query: EvalTable<'_>,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    cache: &mut AggCache<'_, '_>,
) -> Result<Accumulator, EvalError> {
    let target = query.target(target_name)?;
    let target_fk = find_attr(&target.schema().attrs, &on.fk_attr)?;
    let AttrType::Ref { table: group_table } = &target_fk.ty else {
        return Err(EvalError::new("aggregate target join is not Ref-typed"));
    };
    let group_count = snapshot.row_count(query.box_name(), group_table)?;
    let filter = eval_expr(
        filter,
        target,
        &target.schema().attrs,
        snapshot,
        params,
        cache,
        Some(&RuntimeType::Bool),
    )?;
    let InternalColumn::Bool(filter) = filter else {
        return Err(EvalError::new("aggregate filter did not evaluate to Bool"));
    };

    match op {
        AggOp::Count => {
            let mut groups = vec![0_i64; group_count];
            for (row, include) in filter.iter().copied().enumerate() {
                if include {
                    let group = snapshot.reference(
                        target.box_name(),
                        target.table_name(),
                        &on.fk_attr,
                        row,
                    )? as usize;
                    groups[group] = groups[group].checked_add(1).ok_or_else(|| {
                        EvalError::new(format!("aggregate Count overflow in group {group}"))
                    })?;
                }
            }
            Ok(Accumulator::Int(groups))
        }
        AggOp::Sum { value } => {
            let values = eval_expr(
                value,
                target,
                &target.schema().attrs,
                snapshot,
                params,
                cache,
                None,
            )?;
            match values {
                InternalColumn::Int(values) => {
                    let mut groups = vec![0_i64; group_count];
                    for (row, (include, value)) in filter.iter().copied().zip(values).enumerate() {
                        if include {
                            let group = snapshot.reference(
                                target.box_name(),
                                target.table_name(),
                                &on.fk_attr,
                                row,
                            )? as usize;

text:
//! Deterministic, snapshot-isolated synchronous box composition.

use std::cmp::Ordering;
use std::error::Error;
use std::fmt;

use sembla_ir::{
    AggOp, AttrType, ClaimOrdering, Effect, Expr, OutputBuilder, SummaryReduce, ValidatedModel,
    ViewReduce,
};

use crate::eval::{
    eval_column, eval_typed_ref_column, AggCache, EvalError, EvalTable, ParamEnv, ValueColumn,
};
use crate::rng::exp_f64;
use crate::state::{ColumnData, InputTable, Snapshot, StateError, StateStore};

/// A numeric observation scalar. Real equality is bitwise so report equality
/// remains an exact determinism check, including signed zero and NaN payloads.
#[derive(Clone, Copy, Debug)]
pub enum ObservationValue {
    Real(f64),
    Int(i64),
}

impl PartialEq for ObservationValue {
    fn eq(&self, other: &Self) -> bool {
        match (self, other) {
            (Self::Real(left), Self::Real(right)) => left.to_bits() == right.to_bits(),
            (Self::Int(left), Self::Int(right)) => left == right,
            _ => false,
        }
    }
}

impl Eq for ObservationValue {}

/// One declaration-ordered view value from a committed post-tick state.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct ViewValue {
    pub box_name: String,
    pub name: String,
    pub value: ObservationValue,
}

/// One model-declaration-ordered summary value folded across a run.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct SummaryValue {
    pub name: String,
    pub value: ObservationValue,
}

/// Observable result of one committed tick.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct TickReport {
    pub tick: u32,
    /// View values in box order and then view declaration order.
    pub views: Vec<ViewValue>,
    /// Model-global rule counts, retained for single-box API compatibility.
    pub fired: Vec<(u32, usize)>,
    /// Counts grouped in box declaration order for composed-model reporting.
    pub fired_per_box: Vec<(String, Vec<(u32, usize)>)>,
    pub deferred_per_resource_table: Vec<(String, usize)>,
    /// PRD 0005 group-by accumulators built across all boxes for this tick.
    /// A cached aggregate contributes once regardless of querying row count.
    pub aggregate_builds: usize,
}

/// A structured saturation warning produced by [`run`].
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct SaturationWarning {
    pub tick: u32,
    pub table: String,
    pub deferred_count: usize,
    pub fired_count: usize,
}

/// Observable result of a multi-tick run.
#[derive(Clone, Debug, PartialEq, Eq)]
pub struct RunReport {
    pub ticks: Vec<TickReport>,
    pub summaries: Vec<SummaryValue>,
    pub warnings: Vec<SaturationWarning>,
}

/// A deterministic tick execution failure.
#[derive(Clone, Debug, PartialEq, Eq)]
pub enum TickError {
    UnsupportedBoxCount {
        found: usize,
    },
    Evaluation(String),
    State(String),
    InvalidRuntimeType {
        context: String,
        found: String,
    },
    EntityIdOverflow {
        rule_id: u32,
        row: usize,
    },
    IncompatibleClaimOrdering {
        table: String,
        row: u32,
    },
    DoubleWrite {
        box_name: Box<str>,
        table: Box<str>,
        attr: Box<str>,
        row: usize,
        first_rule_id: u32,
        first_transition: Box<str>,
        second_rule_id: u32,
        second_transition: Box<str>,
    },
}

impl fmt::Display for TickError {
    fn fmt(&self, formatter: &mut fmt::Formatter<'_>) -> fmt::Result {
        match self {
            Self::UnsupportedBoxCount { found } => write!(
                formatter,
                "tick executor requires exactly one box, found {found}"
            ),
            Self::Evaluation(message) => write!(formatter, "expression evaluation failed: {message}"),
            Self::State(message) => write!(formatter, "state operation failed: {message}"),
            Self::InvalidRuntimeType { context, found } => {
                write!(formatter, "{context} evaluated to {found}")
            }
            Self::EntityIdOverflow { rule_id, row } => write!(
                formatter,
                "rule {rule_id} row {row} cannot be represented as a u32 entity ID"
            ),
            Self::IncompatibleClaimOrdering { table, row } => write!(
                formatter,
                "resource '{table}' row {row} has incompatible claim ordering modes or key types"
            ),
            Self::DoubleWrite {
                box_name,
                table,
                attr,
                row,
                first_rule_id,
                first_transition,
                second_rule_id,
                second_transition,
            } => write!(
                formatter,
                "double write to {box_name}.{table}.{attr}[{row}] by transition '{first_transition}' (rule {first_rule_id}) and transition '{second_transition}' (rule {second_rule_id})"
            ),
        }
    }
}

impl Error for TickError {}

impl From<EvalError> for TickError {
    fn from(error: EvalError) -> Self {
        Self::Evaluation(error.to_string())
    }
}

impl From<StateError> for TickError {
    fn from(error: StateError) -> Self {
        Self::State(error.to_string())
    }
}

#[derive(Clone, Debug)]
struct Candidate {
    rule_id: u32,
    table_index: usize,
    entity_id: u32,
    row: usize,
    claims: Vec<CandidateClaim>,
}

#[derive(Clone, Debug)]
struct CandidateClaim {
    table_index: usize,
    resource_row: u32,
    ordering: OrderingValue,
}

#[derive(Clone, Debug)]
enum OrderingValue {
    RaceTime(f64),
    Real(f64),
    Int(i64),
    Enum {
        table_index: usize,
        attr_index: usize,
        value: u16,
    },
}

#[derive(Clone, Copy, Debug)]
struct ClaimInstance {
    candidate_index: usize,
    claim_index: usize,
}

#[derive(Clone, Debug)]
enum PendingValue {
    Real(f64),
    Int(i64),
    Enum(u16),
    Ref(u32),
}

#[derive(Clone, Debug)]
struct PendingWrite {
    box_index: usize,
    table_index: usize,
    attr_index: usize,
    row: usize,
    value: PendingValue,
    rule_id: u32,
    transition_name: String,
}

struct TickOutcome {
    report: TickReport,
    fired_per_resource_table: Vec<(String, usize)>,
}

struct BoxOutcome {
    pending: Vec<PendingWrite>,
    fired: Vec<(u32, usize)>,
    deferred: Vec<usize>,
    fired_per_resource_table: Vec<usize>,
    aggregate_builds: usize,
}

struct Resolution {
    fires: Vec<bool>,
    deferred: Vec<usize>,
    fired_per_resource_table: Vec<usize>,
}

/// Executes and commits one deterministic, snapshot-isolated tick.
pub fn run_tick(
    model: &ValidatedModel,
    state: &mut StateStore,
    params: &ParamEnv,
    seed: u64,
    tick: u32,
) -> Result<TickReport, TickError> {
    Ok(execute_tick(model, state, params, seed, tick)?.report)
}

/// Executes ticks `0..n_ticks` and records strict saturation warnings.
pub fn run(
    model: &ValidatedModel,
    state: &mut StateStore,
    params: &ParamEnv,
    seed: u64,
    n_ticks: u32,
) -> Result<RunReport, TickError> {
    let mut ticks = Vec::with_capacity(n_ticks as usize);
    let mut warnings = Vec::new();
    for tick in 0..n_ticks {
        let outcome = execute_tick(model, state, params, seed, tick)?;
        for (table, deferred_count) in &outcome.report.deferred_per_resource_table {
            let fired_count = outcome
                .fired_per_resource_table
                .iter()
                .find(|(name, _)| name == table)
                .map_or(0, |(_, count)| *count);
            if exceeds_saturation_threshold(*deferred_count, fired_count) {
                let warning = SaturationWarning {
                    tick,
                    table: table.clone(),
                    deferred_count: *deferred_count,
                    fired_count,
                };
                eprintln!(
                    "warning: tick {} resource table '{}': {} deferred exceeds 10% of {} fired",
                    warning.tick, warning.table, warning.deferred_count, warning.fired_count
                );
                warnings.push(warning);
            }
        }
        ticks.push(outcome.report);
    }
    let summaries = summarize(model, &ticks)?;
    Ok(RunReport {
        ticks,
        summaries,
        warnings,
    })
}

fn exceeds_saturation_threshold(deferred: usize, fired: usize) -> bool {
    (deferred as u128) * 10 > fired as u128
}

fn execute_tick(
    model: &ValidatedModel,
    state: &mut StateStore,
    params: &ParamEnv,
    seed: u64,
    tick: u32,
) -> Result<TickOutcome, TickError> {
    let snapshot = state.snapshot();
    let mut box_outcomes = Vec::with_capacity(model.model().boxes.len());
    for box_index in 0..model.model().boxes.len() {
        box_outcomes.push(stage_box(model, box_index, &snapshot, params, seed, tick)?);
    }

    let pending: Vec<_> = box_outcomes
        .iter_mut()
        .flat_map(|outcome| std::mem::take(&mut outcome.pending))
        .collect();
    detect_double_writes(&pending, model)?;
    let apply_result = {
        let mut writes = state.write_buffer()?;
        pending.iter().try_for_each(|write| {
            let model_box = &model.model().boxes[write.box_index];
            let table = &model_box.tables[write.table_index];
            let attr = &table.attrs[write.attr_index];
            match &write.value {
                PendingValue::Real(value) => {
                    writes.set_real(&model_box.name, &table.name, &attr.name, write.row, *value)
                }
                PendingValue::Int(value) => {
                    writes.set_int(&model_box.name, &table.name, &attr.name, write.row, *value)
                }
                PendingValue::Enum(value) => {
                    writes.set_enum(&model_box.name, &table.name, &attr.name, write.row, *value)
                }
                PendingValue::Ref(value) => {
                    writes.set_ref(&model_box.name, &table.name, &attr.name, write.row, *value)
                }
            }
        })
    };
    if let Err(error) = apply_result {
        state.discard_writes();
        return Err(error.into());
    }
    // Moore-machine outputs observe the prospective new state, but output
    // construction is fallible. Build every delivered table before commit so
    // an overflow or evaluation error leaves both old state and old inputs
    // unchanged.
    let next_inputs = match state
        .prepared_snapshot()
        .map_err(TickError::from)
        .and_then(|prepared| build_next_inputs(model, &prepared, params))
    {
        Ok(inputs) => inputs,
        Err(error) => {
            state.discard_writes();
            return Err(error);
        }
    };
    if let Err(error) = state.commit() {
        state.discard_writes();
        return Err(error.into());
    }
    state.replace_inputs(next_inputs);
    // Observation is deliberately evaluated only after commit and receives an
    // immutable store. It cannot consume RNG coordinates, stage writes, or
    // influence conflict resolution or scheduling.
    let views = evaluate_views(model, state, params)?;

    let mut fired = model
        .transitions()
        .iter()
        .map(|transition| (transition.rule_id, 0))
        .collect::<Vec<_>>();
    let mut fired_per_box = Vec::with_capacity(box_outcomes.len());
    let mut deferred_per_resource_table = Vec::new();
    let mut fired_per_resource_table = Vec::new();
    let mut aggregate_builds = 0;
    let qualify = model.model().boxes.len() > 1;
    for (box_index, outcome) in box_outcomes.into_iter().enumerate() {
        let model_box = &model.model().boxes[box_index];
        for (rule_id, count) in &outcome.fired {
            fired[*rule_id as usize].1 = *count;
        }
        fired_per_box.push((model_box.name.clone(), outcome.fired));
        aggregate_builds += outcome.aggregate_builds;
        for (table_index, count) in outcome.deferred.into_iter().enumerate() {
            let name = report_table_name(model_box, table_index, qualify);
            if count != 0 {
                deferred_per_resource_table.push((name.clone(), count));
            }
            fired_per_resource_table.push((name, outcome.fired_per_resource_table[table_index]));
        }
    }

    Ok(TickOutcome {
        report: TickReport {
            tick,
            views,
            fired,
            fired_per_box,
            deferred_per_resource_table,
            aggregate_builds,
        },
        fired_per_resource_table,
    })
}

fn evaluate_views(
    model: &ValidatedModel,
    state: &StateStore,
    params: &ParamEnv,
) -> Result<Vec<ViewValue>, TickError> {
    let snapshot = state.snapshot();
    let mut cache = AggCache::new(model, &snapshot, params);
    let mut observations = Vec::new();
    for model_box in &model.model().boxes {
        for view in &model_box.views {
            let table = EvalTable::new(model, &model_box.name, &view.table)?;
            let row_count = snapshot.row_count(&model_box.name, &view.table)?;
            let selected = match &view.filter {
                Some(filter) => match eval_column(filter, table, &snapshot, params, &mut cache)? {
                    ValueColumn::Bool(values) => values,
                    other => return Err(runtime_type("view filter", &other)),
                },
                None => vec![true; row_count],
            };
            let value = match view.reduce {
                ViewReduce::Count => ObservationValue::Int(
                    i64::try_from(selected.iter().filter(|selected| **selected).count()).map_err(
                        |_| {
                            TickError::Evaluation(format!(
                                "view '{}.{}' count exceeds i64",
                                model_box.name, view.name
                            ))
                        },
                    )?,
                ),
                ViewReduce::Sum | ViewReduce::Min | ViewReduce::Max => {
                    let expression = view
                        .value
                        .as_ref()
                        .expect("validated numeric view has a value");
                    let column = eval_column(expression, table, &snapshot, params, &mut cache)?;
                    reduce_view_column(&model_box.name, &view.name, view.reduce, column, &selected)?
                }
            };
            observations.push(ViewValue {
                box_name: model_box.name.clone(),
                name: view.name.clone(),
                value,
            });
        }
    }
    Ok(observations)
}

fn reduce_view_column(
    box_name: &str,
    view_name: &str,
    reduce: ViewReduce,
    column: ValueColumn,
    selected: &[bool],
) -> Result<ObservationValue, TickError> {
    match column {
        ValueColumn::Int(values) => {
            let mut result = match reduce {
                ViewReduce::Sum => 0_i64,
                ViewReduce::Min => i64::MAX,
                ViewReduce::Max => i64::MIN,
                ViewReduce::Count => unreachable!("count does not evaluate a value"),
            };
            for value in values
                .into_iter()
                .zip(selected)
                .filter_map(|(value, selected)| selected.then_some(value))
            {
                result = match reduce {
                    ViewReduce::Sum => result.checked_add(value).ok_or_else(|| {
                        TickError::Evaluation(format!(
                            "view '{box_name}.{view_name}' integer sum overflowed"
                        ))
                    })?,
                    ViewReduce::Min => result.min(value),
                    ViewReduce::Max => result.max(value),
                    ViewReduce::Count => unreachable!(),
                };
            }
            Ok(ObservationValue::Int(result))
        }
        ValueColumn::Real(values) => {
            let mut result = match reduce {
                ViewReduce::Sum => 0.0,
                ViewReduce::Min => f64::INFINITY,
                ViewReduce::Max => f64::NEG_INFINITY,
                ViewReduce::Count => unreachable!("count does not evaluate a value"),
            };
            for value in values
                .into_iter()
                .zip(selected)
                .filter_map(|(value, selected)| selected.then_some(value))
            {
                result = match reduce {
                    ViewReduce::Sum => result + value,
                    ViewReduce::Min if value.total_cmp(&result) == Ordering::Less => value,
                    ViewReduce::Max if value.total_cmp(&result) == Ordering::Greater => value,
                    ViewReduce::Min | ViewReduce::Max => result,
                    ViewReduce::Count => unreachable!(),
                };
            }
            Ok(ObservationValue::Real(result))
        }
        other => Err(runtime_type("view value", &other)),
    }
}

/// Folds model-declared summaries over tick view values in tick order.
pub fn summarize(
    model: &ValidatedModel,
    ticks: &[TickReport],
) -> Result<Vec<SummaryValue>, TickError> {
    let mut summaries = Vec::with_capacity(model.model().summaries.len());
    for declaration in &model.model().summaries {
        let values = ticks
            .iter()
            .map(|tick| {
                tick.views
                    .iter()
                    .find(|view| {
                        view.box_name == declaration.r#box && view.name == declaration.view
                    })
                    .map(|view| (tick.tick, view.value))
                    .ok_or_else(|| {
                        TickError::Evaluation(format!(
                            "summary '{}' could not find view '{}.{}' at tick {}",
                            declaration.name, declaration.r#box, declaration.view, tick.tick
                        ))
                    })
            })
            .collect::<Result<Vec<_>, _>>()?;
        let value = fold_summary(&declaration.name, declaration.reduce, &values)?;
        summaries.push(SummaryValue {
            name: declaration.name.clone(),
            value,
        });
    }
    Ok(summaries)
}

fn fold_summary(
    name: &str,
    reduce: SummaryReduce,
    values: &[(u32, ObservationValue)],
) -> Result<ObservationValue, TickError> {
    let Some(&(first_tick, first_value)) = values.first() else {
        return Err(TickError::Evaluation(format!(
            "summary '{name}' cannot reduce an empty run"
        )));
    };
    match reduce {
        SummaryReduce::Last => Ok(values.last().expect("nonempty").1),
        SummaryReduce::ArgmaxTick => {
            let mut best_tick = first_tick;
            let mut best_value = first_value;
            for &(tick, value) in &values[1..] {
                if observation_cmp(value, best_value)? == Ordering::Greater {
                    best_tick = tick;
                    best_value = value;
                }
            }
            Ok(ObservationValue::Int(i64::from(best_tick)))
        }
        SummaryReduce::Sum => match first_value {
            ObservationValue::Int(_) => {
                let mut total = 0_i64;
                for &(_, value) in values {
                    let ObservationValue::Int(value) = value else {
                        return Err(summary_type_mismatch(name));
                    };
                    total = total.checked_add(value).ok_or_else(|| {
                        TickError::Evaluation(format!("summary '{name}' integer sum overflowed"))
                    })?;
                }
                Ok(ObservationValue::Int(total))
            }
            ObservationValue::Real(_) => {
                let mut total = 0.0;
                for &(_, value) in values {
                    let ObservationValue::Real(value) = value else {
                        return Err(summary_type_mismatch(name));
                    };
                    total += value;
                }
                Ok(ObservationValue::Real(total))
            }
        },
        SummaryReduce::Min | SummaryReduce::Max => {
            let mut result = first_value;
            for &(_, value) in &values[1..] {
                let ordering = observation_cmp(value, result)?;
                if (reduce == SummaryReduce::Min && ordering == Ordering::Less)
                    || (reduce == SummaryReduce::Max && ordering == Ordering::Greater)
                {
                    result = value;
                }
            }
            Ok(result)
        }
    }
}

fn observation_cmp(left: ObservationValue, right: ObservationValue) -> Result<Ordering, TickError> {
    match (left, right) {
        (ObservationValue::Int(left), ObservationValue::Int(right)) => Ok(left.cmp(&right)),
        (ObservationValue::Real(left), ObservationValue::Real(right)) => Ok(left.total_cmp(&right)),
        _ => Err(TickError::Evaluation(
            "observation values changed numeric type across ticks".to_owned(),
        )),
    }
}

fn summary_type_mismatch(name: &str) -> TickError {
    TickError::Evaluation(format!(
        "summary '{name}' source changed numeric type across ticks"
    ))
}

fn report_table_name(model_box: &sembla_ir::Box, table_index: usize, qualify: bool) -> String {
    if qualify {
        format!("{}.{}", model_box.name, model_box.tables[table_index].name)
    } else {
        model_box.tables[table_index].name.clone()
    }
}

fn stage_box(
    model: &ValidatedModel,
    box_index: usize,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    seed: u64,
    tick: u32,
) -> Result<BoxOutcome, TickError> {
    let model_box = &model.model().boxes[box_index];
    let transitions: Vec<_> = model
        .transitions()
        .iter()
        .filter(|transition| transition.box_index == box_index)
        .collect();
    let mut cache = AggCache::new(model, snapshot, params);
    let mut candidates = Vec::new();
    for validated in &transitions {
        let transition = &model_box.transitions[validated.transition_index];
        let table_index = model_box
            .tables
            .iter()
            .position(|table| table.name == transition.table)
            .expect("validated transition table disappeared");
        let table = EvalTable::new(model, &model_box.name, &transition.table)?;
        let guards = match eval_column(&transition.guard, table, snapshot, params, &mut cache)? {
            ValueColumn::Bool(values) => values,
            other => return Err(runtime_type("transition guard", &other)),
        };
        let hazards = match eval_column(&transition.hazard, table, snapshot, params, &mut cache)? {
            ValueColumn::Real(values) => values,
            other => return Err(runtime_type("transition hazard", &other)),
        };
        let mut claim_columns = Vec::with_capacity(transition.contests.len());
        for claim in &transition.contests {
            let resources =
                eval_typed_ref_column(&claim.resource, table, snapshot, params, &mut cache)?;
            let resource_table_index = model_box
                .tables
                .iter()
                .position(|schema| schema.name == resources.target_table)
                .expect("validated Ref target table disappeared");
            let ordering = match &claim.ordering {
                ClaimOrdering::RaceTime => None,
                ClaimOrdering::Key { expr } => {
                    Some(eval_column(expr, table, snapshot, params, &mut cache)?)
                }
            };
            claim_columns.push((resource_table_index, resources.values, ordering, claim));
        }
        for (row, (guard, lambda)) in guards.into_iter().zip(hazards).enumerate() {
            if !guard || lambda.partial_cmp(&0.0) != Some(Ordering::Greater) {
                continue;
            }
            let entity_id = u32::try_from(row).map_err(|_| TickError::EntityIdOverflow {
                rule_id: validated.rule_id,
                row,
            })?;
            let race_time = exp_f64(seed, tick, validated.rule_id, entity_id, 0, lambda);
            if race_time.partial_cmp(&model.model().dt) != Some(Ordering::Less) {
                continue;
            }
            let mut claims = Vec::with_capacity(claim_columns.len());
            for (resource_table, resources, key_column, claim) in &claim_columns {
                let ordering = match (&claim.ordering, key_column) {
                    (ClaimOrdering::RaceTime, None) => OrderingValue::RaceTime(race_time),
                    (ClaimOrdering::Key { expr }, Some(column)) => {
                        key_at(column, expr, table_index, model_box, row)?
                    }
                    _ => unreachable!("claim ordering column construction is exhaustive"),
                };
                claims.push(CandidateClaim {
                    table_index: *resource_table,
                    resource_row: resources[row],
                    ordering,
                });
            }
            candidates.push(Candidate {
                rule_id: validated.rule_id,
                table_index,
                entity_id,
                row,
                claims,
            });
        }
    }
    let resolution = resolve_claims(&candidates, model_box.tables.len(), model_box)?;
    let mut pending = Vec::new();
    for validated in &transitions {
        let transition = &model_box.transitions[validated.transition_index];
        let winner_indices: Vec<usize> = candidates
            .iter()
            .enumerate()
            .filter(|(index, candidate)| {
                candidate.rule_id == validated.rule_id && resolution.fires[*index]
            })
            .map(|(index, _)| index)
            .collect();
        if winner_indices.is_empty() {
            continue;
        }
        let table = EvalTable::new(model, &model_box.name, &transition.table)?;
        let table_index = candidates[winner_indices[0]].table_index;
        let schema = &model_box.tables[table_index];
        let mut effect_columns = Vec::with_capacity(transition.effects.len());
        for effect in &transition.effects {
            let Effect::SetAttr { attr, value } = effect;
            let attr_index = schema
                .attrs
                .iter()
                .position(|declaration| declaration.name == *attr)
                .expect("validated effect attribute disappeared");
            let destination = &schema.attrs[attr_index];
            let value = match &destination.ty {
                AttrType::Ref { .. } => PendingColumn::Ref(
                    eval_typed_ref_column(value, table, snapshot, params, &mut cache)?.values,
                ),
                _ => PendingColumn::Value(eval_column(
                    value,
                    table.with_expected_attr(attr)?,
                    snapshot,
                    params,
                    &mut cache,
                )?),
            };
            effect_columns.push((attr_index, value));
        }
        for candidate_index in winner_indices {
            let candidate = &candidates[candidate_index];
            for (attr_index, values) in &effect_columns {
                pending.push(PendingWrite {
                    box_index,
                    table_index,
                    attr_index: *attr_index,
                    row: candidate.row,
                    value: values.at(candidate.row)?,
                    rule_id: candidate.rule_id,
                    transition_name: transition.name.clone(),
                });
            }
        }
    }
    let mut fired = transitions
        .iter()
        .map(|transition| (transition.rule_id, 0))
        .collect::<Vec<_>>();
    for (candidate, fire) in candidates.iter().zip(&resolution.fires) {
        if *fire {
            let entry = fired
                .iter_mut()
                .find(|(rule_id, _)| *rule_id == candidate.rule_id)
                .expect("candidate has validated transition");
            entry.1 += 1;
        }
    }
    Ok(BoxOutcome {
        pending,
        fired,
        deferred: resolution.deferred,
        fired_per_resource_table: resolution.fired_per_resource_table,
        aggregate_builds: cache.build_count(),
    })
}

fn build_next_inputs(
    model: &ValidatedModel,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
) -> Result<Vec<InputTable>, TickError> {
    let mut inputs = model
        .model()
        .boxes
        .iter()
        .flat_map(|model_box| {
            model_box
                .inputs
                .iter()
                .map(|input| InputTable::empty(&model_box.name, &input.name, &input.schema))
        })
        .collect::<Vec<_>>();
    for wire in &model.model().wires {
        let source_box = model
            .model()
            .boxes
            .iter()
            .find(|model_box| model_box.name == wire.from.r#box)
            .expect("validated wire source box disappeared");
        let output = source_box
            .outputs
            .iter()
            .find(|output| output.name == wire.from.port)
            .expect("validated wire source port disappeared");
        let built = build_output(model, snapshot, params, source_box, output)?;
        let destination = inputs
            .iter_mut()
            .find(|input| input.box_name == wire.to.r#box && input.port_name == wire.to.port)
            .expect("validated wire destination disappeared");
        destination.row_count = built.row_count;
        destination.columns = built.columns;
    }
    Ok(inputs)
}

fn build_output(
    model: &ValidatedModel,
    snapshot: &Snapshot<'_>,
    params: &ParamEnv,
    model_box: &sembla_ir::Box,
    output: &sembla_ir::OutputDecl,
) -> Result<InputTable, TickError> {
    let OutputBuilder::PerTable { table, fields } = &output.builder;
    let eval_table = EvalTable::new(model, &model_box.name, table)?;
    let rows = snapshot.row_count(&model_box.name, table)?;
    let mut cache = AggCache::new(model, snapshot, params);
    let mut columns = Vec::with_capacity(fields.len());
    for field in fields {
        let selected = match &field.filter {
            Some(filter) => match eval_column(filter, eval_table, snapshot, params, &mut cache)? {
                ValueColumn::Bool(values) => values,
                other => return Err(runtime_type("output filter", &other)),
            },
            None => vec![true; rows],
        };
        let column = match &field.op {
            AggOp::Count => {
                let count = selected.iter().filter(|value| **value).count();
                ColumnData::Int(vec![i64::try_from(count).map_err(|_| {
                    TickError::Evaluation("output count exceeds i64".to_owned())
                })?])
            }
            AggOp::Sum { value } => {
                match eval_column(value, eval_table, snapshot, params, &mut cache)? {
                    ValueColumn::Real(values) => ColumnData::Real(vec![values
                        .into_iter()
                        .zip(&selected)
                        .filter(|(_, selected)| **selected)
                        .map(|(value, _)| value)
                        .fold(0.0, |sum, value| sum + value)]),
                    ValueColumn::Int(values) => {
                        let mut sum = 0_i64;
                        for (row, (value, selected)) in
                            values.into_iter().zip(&selected).enumerate()
                        {
                            if *selected {
                                sum = sum.checked_add(value).ok_or_else(|| {
                                    TickError::Evaluation(format!(
                                        "output integer sum overflow at row {row}"
                                    ))
                                })?;
                            }
                        }
                        ColumnData::Int(vec![sum])
                    }
                    other => return Err(runtime_type("output Sum", &other)),
                }
            }
        };
        columns.push(column);
    }
    Ok(InputTable {
        box_name: model_box.name.clone(),
        port_name: output.name.clone(),
        schema: output.schema.clone(),
        row_count: 1,
        columns,
    })
}

fn runtime_type(context: &str, column: &ValueColumn) -> TickError {
    let found = match column {
        ValueColumn::Real(_) => "Real",
        ValueColumn::Int(_) => "Int",
        ValueColumn::Bool(_) => "Bool",
        ValueColumn::Enum(_) => "Enum",
    };
    TickError::InvalidRuntimeType {
        context: context.to_owned(),
        found: found.to_owned(),
    }
}

fn key_at(
    column: &ValueColumn,
    expr: &Expr,
    table_index: usize,
    model_box: &sembla_ir::Box,
    row: usize,
) -> Result<OrderingValue, TickError> {
    match column {
        ValueColumn::Real(values) => Ok(OrderingValue::Real(values[row])),
        ValueColumn::Int(values) => Ok(OrderingValue::Int(values[row])),
        ValueColumn::Enum(values) => {
            let Expr::SelfAttr { name } = expr else {
                return Err(TickError::Evaluation(
                    "Enum contest key has no source attribute identity".to_owned(),
                ));
            };
            let attr_index = model_box.tables[table_index]
                .attrs
                .iter()
                .position(|attr| attr.name == *name)
                .expect("validated key attribute disappeared");
            Ok(OrderingValue::Enum {
                table_index,
                attr_index,
                value: values[row],
            })
        }
        ValueColumn::Bool(_) => Err(runtime_type("contest key", column)),
    }
}

fn resolve_claims(
    candidates: &[Candidate],
    table_count: usize,
    model_box: &sembla_ir::Box,
) -> Result<Resolution, TickError> {
    let mut instances = Vec::new();
    for (candidate_index, candidate) in candidates.iter().enumerate() {
        for claim_index in 0..candidate.claims.len() {
            instances.push(ClaimInstance {
                candidate_index,
                claim_index,
            });
        }
    }
    instances.sort_by(|lhs, rhs| {
        let lhs_candidate = &candidates[lhs.candidate_index];
        let rhs_candidate = &candidates[rhs.candidate_index];
        let lhs_claim = &lhs_candidate.claims[lhs.claim_index];
        let rhs_claim = &rhs_candidate.claims[rhs.claim_index];
        (
            lhs_claim.table_index,
            lhs_claim.resource_row,
            lhs_candidate.rule_id,
            lhs_candidate.entity_id,
        )
            .cmp(&(
                rhs_claim.table_index,
                rhs_claim.resource_row,
                rhs_candidate.rule_id,
                rhs_candidate.entity_id,
            ))
            .then(lhs.claim_index.cmp(&rhs.claim_index))
    });

    let mut won_all = vec![true; candidates.len()];
    let mut deferred_table = vec![vec![false; table_count]; candidates.len()];
    let mut start = 0;
    while start < instances.len() {
        let first = instances[start];
        let first_claim = &candidates[first.candidate_index].claims[first.claim_index];
        let mut end = start + 1;
        while end < instances.len() {
            let claim =
                &candidates[instances[end].candidate_index].claims[instances[end].claim_index];
            if (claim.table_index, claim.resource_row)
                != (first_claim.table_index, first_claim.resource_row)
            {
                break;
            }
            end += 1;
        }
        let mut winner = first;
        for instance in &instances[start + 1..end] {
            if compare_instances(*instance, winner, candidates, model_box)? == Ordering::Less {
                winner = *instance;
            }
        }
        let winner_candidate = winner.candidate_index;
        for instance in &instances[start..end] {
            if instance.candidate_index != winner_candidate {
                won_all[instance.candidate_index] = false;
                deferred_table[instance.candidate_index][first_claim.table_index] = true;
            }
        }
        start = end;
    }

    let mut deferred = vec![0; table_count];
    let mut fired_per_resource_table = vec![0; table_count];
    for (candidate_index, candidate) in candidates.iter().enumerate() {
        for (table_index, lost) in deferred_table[candidate_index].iter().enumerate() {
            if *lost {
                deferred[table_index] += 1;
            }
        }
        if won_all[candidate_index] {
            let mut counted = vec![false; table_count];
            for claim in &candidate.claims {
                if !counted[claim.table_index] {
                    counted[claim.table_index] = true;
                    fired_per_resource_table[claim.table_index] += 1;
                }
            }
        }
    }
    Ok(Resolution {
        fires: won_all,
        deferred,
        fired_per_resource_table,
    })
}

fn compare_instances(
    lhs: ClaimInstance,
    rhs: ClaimInstance,
    candidates: &[Candidate],
    model_box: &sembla_ir::Box,
) -> Result<Ordering, TickError> {
    let lhs_candidate = &candidates[lhs.candidate_index];
    let rhs_candidate = &candidates[rhs.candidate_index];
    let lhs_claim = &lhs_candidate.claims[lhs.claim_index];
    let rhs_claim = &rhs_candidate.claims[rhs.claim_index];
    let key_order = match (&lhs_claim.ordering, &rhs_claim.ordering) {
        (OrderingValue::RaceTime(lhs), OrderingValue::RaceTime(rhs))
        | (OrderingValue::Real(lhs), OrderingValue::Real(rhs)) => lhs.total_cmp(rhs),
        (OrderingValue::Int(lhs), OrderingValue::Int(rhs)) => lhs.cmp(rhs),
        (
            OrderingValue::Enum {
                table_index: lhs_table,
                attr_index: lhs_attr,
                value: lhs,
            },
            OrderingValue::Enum {
                table_index: rhs_table,
                attr_index: rhs_attr,
                value: rhs,
            },
        ) if enum_domains_match(model_box, *lhs_table, *lhs_attr, *rhs_table, *rhs_attr) => {
            lhs.cmp(rhs)
        }
        _ => {
            return Err(TickError::IncompatibleClaimOrdering {
                table: model_box.tables[lhs_claim.table_index].name.clone(),
                row: lhs_claim.resource_row,
            })
        }
    };
    Ok(key_order.then_with(|| {
        (lhs_candidate.rule_id, lhs_candidate.entity_id)
            .cmp(&(rhs_candidate.rule_id, rhs_candidate.entity_id))
    }))
}

fn enum_domains_match(
    model_box: &sembla_ir::Box,
    lhs_table: usize,
    lhs_attr: usize,
    rhs_table: usize,
    rhs_attr: usize,
) -> bool {
    match (
        &model_box.tables[lhs_table].attrs[lhs_attr].ty,
        &model_box.tables[rhs_table].attrs[rhs_attr].ty,
    ) {
        (
            AttrType::Enum {
                variants: lhs_variants,
            },
            AttrType::Enum {
                variants: rhs_variants,
            },
        ) => lhs_variants == rhs_variants,
        _ => false,
    }
}

enum PendingColumn {
    Value(ValueColumn),
    Ref(Vec<u32>),
}

impl PendingColumn {
    fn at(&self, row: usize) -> Result<PendingValue, TickError> {
        match self {
            Self::Value(ValueColumn::Real(values)) => Ok(PendingValue::Real(values[row])),
            Self::Value(ValueColumn::Int(values)) => Ok(PendingValue::Int(values[row])),
            Self::Value(ValueColumn::Enum(values)) => Ok(PendingValue::Enum(values[row])),
            Self::Ref(values) => Ok(PendingValue::Ref(values[row])),
            Self::Value(ValueColumn::Bool(_)) => Err(TickError::InvalidRuntimeType {
                context: "effect value".to_owned(),
                found: "Bool".to_owned(),
            }),
        }
    }
}

fn detect_double_writes(pending: &[PendingWrite], model: &ValidatedModel) -> Result<(), TickError> {
    let mut order: Vec<usize> = (0..pending.len()).collect();
    order.sort_by_key(|index| {
        let write = &pending[*index];
        (
            write.box_index,
            write.table_index,
            write.attr_index,
            write.row,
        )
    });
    for pair in order.windows(2) {
        let first = &pending[pair[0]];
        let second = &pending[pair[1]];
        if (
            first.box_index,
            first.table_index,
            first.attr_index,
            first.row,
        ) == (
            second.box_index,
            second.table_index,
            second.attr_index,
            second.row,
        ) {
            let model_box = &model.model().boxes[first.box_index];
            return Err(TickError::DoubleWrite {
                box_name: model_box.name.clone().into_boxed_str(),
                table: model_box.tables[first.table_index]
                    .name
                    .clone()
                    .into_boxed_str(),
                attr: model_box.tables[first.table_index].attrs[first.attr_index]
                    .name
                    .clone()
                    .into_boxed_str(),
                row: first.row,
                first_rule_id: first.rule_id,
                first_transition: first.transition_name.clone().into_boxed_str(),
                second_rule_id: second.rule_id,
                second_transition: second.transition_name.clone().into_boxed_str(),
            });
        }
    }
    Ok(())
}

